import React, { useCallback, useEffect, useMemo, useState } from 'react';
import axios from 'axios';
import {
  Alert,
  Box,
  Button,
  Card,
  CardContent,
  CardActions,
  Checkbox,
  Chip,
  CircularProgress,
  Container,
  Divider,
  FormControl,
  FormControlLabel,
  Grid,
  IconButton,
  InputAdornment,
  InputLabel,
  MenuItem,
  Paper,
  Select,
  Stack,
  TextField,
  Typography,
} from '@mui/material';
import AccessTimeRoundedIcon from '@mui/icons-material/AccessTimeRounded';
import AutoAwesomeRoundedIcon from '@mui/icons-material/AutoAwesomeRounded';
import DeleteOutlineRoundedIcon from '@mui/icons-material/DeleteOutlineRounded';
import EditRoundedIcon from '@mui/icons-material/EditRounded';
import FavoriteRoundedIcon from '@mui/icons-material/FavoriteRounded';
import FilterAltRoundedIcon from '@mui/icons-material/FilterAltRounded';
import LocalDiningRoundedIcon from '@mui/icons-material/LocalDiningRounded';
import RestaurantMenuRoundedIcon from '@mui/icons-material/RestaurantMenuRounded';
import SearchRoundedIcon from '@mui/icons-material/SearchRounded';
import SoupKitchenRoundedIcon from '@mui/icons-material/SoupKitchenRounded';

import ConfirmDialog from './ConfirmDialog';
import Notification from './Notification';

const CUISINES = ['Indian', 'Chinese', 'Italian', 'Mexican', 'Continental', 'Other'];
const API_URL = 'http://localhost:4000/recipes';

function getErrorMessage(error) {
  if (axios.isAxiosError(error)) {
    return error.response?.data?.message || error.message || 'Request failed.';
  }
  return 'Something went wrong. Please try again.';
}

function glassPanelSx() {
  return {
    border: '1px solid rgba(255,255,255,0.36)',
    background: 'linear-gradient(130deg, rgba(255,255,255,0.42), rgba(255,255,255,0.14))',
    backdropFilter: 'blur(16px)',
    WebkitBackdropFilter: 'blur(16px)',
    boxShadow: '0 18px 44px rgba(3, 17, 33, 0.22)',
  };
}

function RecipeForm({ onSave, editing, onCancel, busy }) {
  const [form, setForm] = useState({
    name: '',
    ingredients: '',
    steps: '',
    cookingTime: '',
    cuisine: 'Indian',
    isFavorite: false,
  });

  useEffect(() => {
    if (editing) {
      setForm({
        ...editing,
        cookingTime: String(editing.cookingTime),
      });
      return;
    }
    setForm({
      name: '',
      ingredients: '',
      steps: '',
      cookingTime: '',
      cuisine: 'Indian',
      isFavorite: false,
    });
  }, [editing]);

  const handleChange = (event) => {
    const { name, value, type, checked } = event.target;
    setForm((prev) => ({ ...prev, [name]: type === 'checkbox' ? checked : value }));
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    onSave({
      ...form,
      cookingTime: Number(form.cookingTime),
    });
  };

  return (
    <Paper elevation={0} sx={{ p: { xs: 2, md: 3 }, borderRadius: 4, ...glassPanelSx() }}>
      <Stack direction="row" alignItems="center" spacing={1} sx={{ mb: 2 }}>
        <AutoAwesomeRoundedIcon color="primary" />
        <Typography variant="h6" fontWeight={700}>
          {editing ? 'Update Recipe' : 'Create Recipe'}
        </Typography>
      </Stack>

      <Box component="form" onSubmit={handleSubmit}>
        <Grid container spacing={2}>
          <Grid item xs={12} md={6}>
            <TextField
              label="Recipe Name"
              name="name"
              value={form.name}
              onChange={handleChange}
              fullWidth
              required
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <LocalDiningRoundedIcon fontSize="small" color="action" />
                  </InputAdornment>
                ),
              }}
            />
          </Grid>

          <Grid item xs={12} md={6}>
            <FormControl fullWidth>
              <InputLabel>Cuisine</InputLabel>
              <Select name="cuisine" value={form.cuisine} label="Cuisine" onChange={handleChange}>
                {CUISINES.map((cuisine) => (
                  <MenuItem key={cuisine} value={cuisine}>
                    {cuisine}
                  </MenuItem>
                ))}
              </Select>
            </FormControl>
          </Grid>

          <Grid item xs={12} md={6}>
            <TextField
              label="Cooking Time (minutes)"
              name="cookingTime"
              value={form.cookingTime}
              onChange={handleChange}
              type="number"
              inputProps={{ min: 1 }}
              fullWidth
              required
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <AccessTimeRoundedIcon fontSize="small" color="action" />
                  </InputAdornment>
                ),
              }}
            />
          </Grid>

          <Grid item xs={12} md={6}>
            <FormControlLabel
              control={<Checkbox name="isFavorite" checked={form.isFavorite} onChange={handleChange} color="error" />}
              label="Pin as Favorite"
              sx={{ mt: 0.5 }}
            />
          </Grid>

          <Grid item xs={12}>
            <TextField
              label="Ingredients"
              name="ingredients"
              value={form.ingredients}
              onChange={handleChange}
              fullWidth
              required
              multiline
              minRows={2}
              placeholder="Example: 2 tomatoes, olive oil, basil"
            />
          </Grid>

          <Grid item xs={12}>
            <TextField
              label="Steps"
              name="steps"
              value={form.steps}
              onChange={handleChange}
              fullWidth
              required
              multiline
              minRows={3}
              placeholder="Describe the method in clear steps"
            />
          </Grid>

          <Grid item xs={12}>
            <Stack direction="row" spacing={1.5}>
              <Button type="submit" variant="contained" disabled={busy}>
                {editing ? 'Save Changes' : 'Add Recipe'}
              </Button>
              {editing && (
                <Button variant="outlined" onClick={onCancel} disabled={busy}>
                  Cancel
                </Button>
              )}
            </Stack>
          </Grid>
        </Grid>
      </Box>
    </Paper>
  );
}

function RecipeCard({ recipe, onEdit, onDelete, onToggleFavorite, busy }) {
  return (
    <Card
      sx={{
        borderRadius: 3,
        ...glassPanelSx(),
        borderColor: recipe.isFavorite ? 'rgba(255, 93, 93, 0.55)' : 'rgba(255,255,255,0.35)',
      }}
    >
      <CardContent>
        <Stack direction="row" justifyContent="space-between" alignItems="center" spacing={1} sx={{ mb: 1.2 }}>
          <Typography variant="h6" fontWeight={700}>
            {recipe.name}
          </Typography>
          {recipe.isFavorite && <Chip label="Favorite" color="error" size="small" />}
        </Stack>

        <Stack direction="row" spacing={1} sx={{ mb: 1.5 }}>
          <Chip icon={<RestaurantMenuRoundedIcon />} label={recipe.cuisine} size="small" />
          <Chip icon={<AccessTimeRoundedIcon />} label={`${recipe.cookingTime} min`} size="small" />
        </Stack>

        <Typography variant="body2" color="text.secondary" sx={{ mb: 0.5 }}>
          <strong>Ingredients:</strong> {recipe.ingredients}
        </Typography>
        <Typography variant="body2" color="text.secondary">
          <strong>Steps:</strong> {recipe.steps}
        </Typography>
      </CardContent>

      <CardActions sx={{ px: 2, pb: 2 }}>
        <IconButton
          onClick={() => onToggleFavorite(recipe)}
          color={recipe.isFavorite ? 'error' : 'default'}
          disabled={busy}
          aria-label="toggle favorite"
        >
          <FavoriteRoundedIcon />
        </IconButton>
        <Button startIcon={<EditRoundedIcon />} onClick={() => onEdit(recipe)} disabled={busy}>
          Edit
        </Button>
        <IconButton onClick={() => onDelete(recipe)} color="error" disabled={busy} aria-label="delete recipe">
          <DeleteOutlineRoundedIcon />
        </IconButton>
      </CardActions>
    </Card>
  );
}

export default function App() {
  const [recipes, setRecipes] = useState([]);
  const [filter, setFilter] = useState({ cuisine: '', search: '', favorite: false });
  const [editing, setEditing] = useState(null);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [deletingRecipe, setDeletingRecipe] = useState(null);
  const [toast, setToast] = useState({ open: false, severity: 'success', message: '' });

  const notify = useCallback((severity, message) => {
    setToast({ open: true, severity, message });
  }, []);

  const fetchRecipes = useCallback(async () => {
    setLoading(true);
    try {
      const params = {};
      if (filter.cuisine) params.cuisine = filter.cuisine;
      if (filter.search.trim()) params.search = filter.search.trim();
      if (filter.favorite) params.favorite = true;

      const response = await axios.get(API_URL, { params });
      setRecipes(response.data);
    } catch (error) {
      notify('error', `Unable to fetch recipes. ${getErrorMessage(error)}`);
    } finally {
      setLoading(false);
    }
  }, [filter.cuisine, filter.favorite, filter.search, notify]);

  useEffect(() => {
    fetchRecipes();
  }, [fetchRecipes]);

  const favoriteCount = useMemo(() => recipes.filter((recipe) => recipe.isFavorite).length, [recipes]);

  const handleSave = async (data) => {
    if (!data.cookingTime || data.cookingTime < 1) {
      notify('warning', 'Cooking time must be at least 1 minute.');
      return;
    }

    setSaving(true);
    try {
      if (editing) {
        await axios.put(`${API_URL}/${editing.id}`, data);
        notify('success', 'Recipe updated successfully.');
        setEditing(null);
      } else {
        await axios.post(API_URL, data);
        notify('success', 'Recipe added successfully.');
      }
      await fetchRecipes();
    } catch (error) {
      notify('error', `Could not save recipe. ${getErrorMessage(error)}`);
    } finally {
      setSaving(false);
    }
  };

  const handleDeleteRequest = (recipe) => {
    setDeletingRecipe(recipe);
  };

  const handleDeleteConfirm = async () => {
    if (!deletingRecipe) return;

    setSaving(true);
    try {
      await axios.delete(`${API_URL}/${deletingRecipe.id}`);
      notify('success', 'Recipe deleted.');
      if (editing?.id === deletingRecipe.id) {
        setEditing(null);
      }
      setDeletingRecipe(null);
      await fetchRecipes();
    } catch (error) {
      notify('error', `Delete failed. ${getErrorMessage(error)}`);
    } finally {
      setSaving(false);
    }
  };

  const handleToggleFavorite = async (recipe) => {
    setSaving(true);
    try {
      await axios.patch(`${API_URL}/${recipe.id}/favorite`, { isFavorite: !recipe.isFavorite });
      notify('success', recipe.isFavorite ? 'Removed from favorites.' : 'Added to favorites.');
      await fetchRecipes();
    } catch (error) {
      notify('error', `Could not update favorite status. ${getErrorMessage(error)}`);
    } finally {
      setSaving(false);
    }
  };

  return (
    <Box
      sx={{
        minHeight: '100vh',
        py: { xs: 3, md: 5 },
        background:
          'radial-gradient(circle at 15% 20%, rgba(77, 171, 247, 0.45) 0%, rgba(77, 171, 247, 0) 32%), radial-gradient(circle at 85% 8%, rgba(167, 139, 250, 0.35) 0%, rgba(167, 139, 250, 0) 28%), linear-gradient(120deg, #0a1929 0%, #122c43 45%, #0a2238 100%)',
      }}
    >
      <Container maxWidth="lg">
        <Paper elevation={0} sx={{ p: { xs: 2.5, md: 3.5 }, mb: 3, borderRadius: 4, ...glassPanelSx() }}>
          <Stack
            direction={{ xs: 'column', md: 'row' }}
            spacing={2}
            alignItems={{ xs: 'flex-start', md: 'center' }}
            justifyContent="space-between"
          >
            <Box>
              <Stack direction="row" alignItems="center" spacing={1} sx={{ mb: 0.5 }}>
                <SoupKitchenRoundedIcon color="primary" />
                <Typography variant="h4" fontWeight={800}>
                  RecipeBox Pro
                </Typography>
              </Stack>
              <Typography variant="body1" color="text.secondary">
                Organize recipes with a clean workflow and polished liquid-glass UI.
              </Typography>
            </Box>

            <Stack direction="row" spacing={1}>
              <Chip icon={<RestaurantMenuRoundedIcon />} label={`${recipes.length} recipes`} />
              <Chip icon={<FavoriteRoundedIcon />} label={`${favoriteCount} favorites`} color="error" />
            </Stack>
          </Stack>
        </Paper>

        <Grid container spacing={2.5}>
          <Grid item xs={12} lg={5}>
            <RecipeForm onSave={handleSave} editing={editing} onCancel={() => setEditing(null)} busy={saving} />
          </Grid>

          <Grid item xs={12} lg={7}>
            <Paper elevation={0} sx={{ p: 2.5, borderRadius: 4, ...glassPanelSx() }}>
              <Stack
                direction={{ xs: 'column', sm: 'row' }}
                spacing={1.5}
                alignItems={{ xs: 'stretch', sm: 'center' }}
                justifyContent="space-between"
                sx={{ mb: 2 }}
              >
                <Stack direction="row" spacing={1} alignItems="center">
                  <FilterAltRoundedIcon color="primary" />
                  <Typography variant="h6" fontWeight={700}>
                    Browse Recipes
                  </Typography>
                </Stack>
              </Stack>

              <Grid container spacing={1.5} sx={{ mb: 2 }}>
                <Grid item xs={12} md={4}>
                  <FormControl fullWidth>
                    <InputLabel>Cuisine</InputLabel>
                    <Select
                      value={filter.cuisine}
                      label="Cuisine"
                      onChange={(event) => setFilter((prev) => ({ ...prev, cuisine: event.target.value }))}
                    >
                      <MenuItem value="">All</MenuItem>
                      {CUISINES.map((cuisine) => (
                        <MenuItem key={cuisine} value={cuisine}>
                          {cuisine}
                        </MenuItem>
                      ))}
                    </Select>
                  </FormControl>
                </Grid>

                <Grid item xs={12} md={5}>
                  <TextField
                    fullWidth
                    label="Search"
                    value={filter.search}
                    onChange={(event) => setFilter((prev) => ({ ...prev, search: event.target.value }))}
                    placeholder="By name or ingredient"
                    InputProps={{
                      startAdornment: (
                        <InputAdornment position="start">
                          <SearchRoundedIcon fontSize="small" color="action" />
                        </InputAdornment>
                      ),
                    }}
                  />
                </Grid>

                <Grid item xs={12} md={3}>
                  <FormControlLabel
                    control={
                      <Checkbox
                        checked={filter.favorite}
                        onChange={(event) => setFilter((prev) => ({ ...prev, favorite: event.target.checked }))}
                        color="error"
                      />
                    }
                    label="Favorites"
                  />
                </Grid>
              </Grid>

              <Divider sx={{ mb: 2 }} />

              {loading ? (
                <Stack alignItems="center" justifyContent="center" sx={{ py: 6 }}>
                  <CircularProgress />
                </Stack>
              ) : recipes.length === 0 ? (
                <Alert severity="info">No recipes match your filters yet.</Alert>
              ) : (
                <Stack spacing={1.8}>
                  {recipes.map((recipe) => (
                    <RecipeCard
                      key={recipe.id}
                      recipe={recipe}
                      onEdit={setEditing}
                      onDelete={handleDeleteRequest}
                      onToggleFavorite={handleToggleFavorite}
                      busy={saving}
                    />
                  ))}
                </Stack>
              )}
            </Paper>
          </Grid>
        </Grid>
      </Container>

      <ConfirmDialog
        open={Boolean(deletingRecipe)}
        title="Delete Recipe"
        content={`Delete ${deletingRecipe?.name || 'this recipe'}? This action cannot be undone.`}
        onClose={() => setDeletingRecipe(null)}
        onConfirm={handleDeleteConfirm}
      />

      <Notification
        open={toast.open}
        onClose={() => setToast((prev) => ({ ...prev, open: false }))}
        severity={toast.severity}
        message={toast.message}
      />
    </Box>
  );
}
